"use strict";(self.webpackChunkreact_restyle_components=self.webpackChunkreact_restyle_components||[]).push([[2707],{"./src/core-components/src/components/Table/Table.stories.tsx":(__unused_webpack_module,__webpack_exports__,__webpack_require__)=>{__webpack_require__.r(__webpack_exports__),__webpack_require__.d(__webpack_exports__,{BasicUsage:()=>BasicUsage,Documentation:()=>Documentation,WithSelectionActions:()=>WithSelectionActions,__namedExportsOrder:()=>__namedExportsOrder,default:()=>__WEBPACK_DEFAULT_EXPORT__});const __WEBPACK_DEFAULT_EXPORT__={title:"Components/Table",component:__webpack_require__("./src/core-components/src/components/Table/Table.tsx").X,tags:["autodocs"],parameters:{componentSubtitle:"import { Table } from 'react-restyle-components'",docs:{description:{component:"\n# Table Component\n\nA comprehensive data table component with sorting, filtering, pagination, row selection, cell editing, and more.\n\n## Features\n- 🔄 Sorting (single/multi column)\n- 🔍 Column filters (text, number, date, select)\n- 🔎 Global search\n- 📄 Pagination (client/server-side)\n- ✅ Row selection (single, multiple, checkbox)\n- ✏️ Inline cell editing\n- 📥 CSV/Excel export\n- 👁️ Column visibility toggle\n- 📱 Responsive design\n- ♿ Full accessibility support\n- 🎯 Dynamic selection actions\n\n## Basic Usage\n\n```tsx\nimport { Table, TableColumn } from 'react-restyle-components';\n\ninterface User {\n  _id: string;\n  name: string;\n  email: string;\n  age: number;\n}\n\nconst columns: TableColumn<User>[] = [\n  { dataField: 'name', text: 'Name', sort: true },\n  { dataField: 'email', text: 'Email', filter: true },\n  { dataField: 'age', text: 'Age', sort: true, filter: true },\n];\n\nconst data: User[] = [\n  { _id: '1', name: 'John Doe', email: 'john@example.com', age: 30 },\n  { _id: '2', name: 'Jane Smith', email: 'jane@example.com', age: 25 },\n];\n\n<Table \n  id=\"my-table\" \n  data={data} \n  columns={columns}\n  pagination\n  searchable\n/>\n```\n\n## Row Selection with Dynamic Actions\n\n```tsx\nimport { Table } from 'react-restyle-components';\nimport { useState } from 'react';\n\nfunction MyTable() {\n  const [selectedRows, setSelectedRows] = useState<User[]>([]);\n\n  return (\n    <Table\n      id=\"my-table\"\n      data={data}\n      columns={columns}\n      isSelectRow\n      onSelectedRow={setSelectedRows}\n      // Built-in select-sort feature\n      isSelectSort\n      onSelectSort={(selectedRows, keys) => {\n        console.log('Move to top:', selectedRows);\n      }}\n      // Custom dynamic actions\n      selectionActions={[\n        {\n          nameIcon: 'FaWhatsapp',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('WhatsApp action', selectedRows);\n            // Your custom logic here\n          },\n          tooltip: 'Send via WhatsApp',\n        },\n        {\n          nameIcon: 'FaTrash',\n          propsIcon: { size: '24', color: '#ff0000' },\n          onClick: (selectedRows, keys) => {\n            console.log('Delete action', selectedRows);\n            // Your custom logic here\n          },\n          tooltip: 'Delete selected',\n        },\n        {\n          nameIcon: 'FaDownload',\n          propsIcon: { size: '24', color: '#fff' },\n          onClick: (selectedRows, keys) => {\n            console.log('Download action', selectedRows);\n            // Your custom logic here\n          },\n          tooltip: 'Download selected',\n        },\n      ]}\n    />\n  );\n}\n```\n\n## Server-Side Pagination\n\n```tsx\n<Table\n  id=\"server-table\"\n  data={currentPageData}\n  columns={columns}\n  pagination\n  remote\n  totalSize={totalRecords}\n  onPageSizeChange={async (page, size) => {\n    // Fetch data from server\n    const response = await fetchData(page, size);\n    setData(response.data);\n    setTotal(response.total);\n  }}\n/>\n```\n\n## Column Filters\n\n```tsx\nimport { TextFilter, NumberFilter, SelectFilter, DateFilter } from './filters';\n\nconst columns: TableColumn<User>[] = [\n  {\n    dataField: 'name',\n    text: 'Name',\n    filter: TextFilter({\n      placeholder: 'Search name...',\n      delay: 300,\n    }),\n  },\n  {\n    dataField: 'age',\n    text: 'Age',\n    filter: NumberFilter({\n      placeholder: 'Enter age...',\n      defaultComparator: '>=',\n    }),\n  },\n  {\n    dataField: 'status',\n    text: 'Status',\n    filter: SelectFilter({\n      placeholder: 'All statuses',\n      options: [\n        { value: 'active', label: 'Active' },\n        { value: 'inactive', label: 'Inactive' },\n      ],\n    }),\n  },\n  {\n    dataField: 'createdAt',\n    text: 'Created Date',\n    filter: DateFilter({\n      defaultRangeMode: true,\n    }),\n  },\n];\n\n<Table\n  id=\"filtered-table\"\n  data={data}\n  columns={columns}\n  filterable\n/>\n```\n\n## Cell Editing\n\n```tsx\nconst columns: TableColumn<User>[] = [\n  {\n    dataField: 'name',\n    text: 'Name',\n    editable: true,\n    onCellEdit: (newValue, row, rowIndex, column) => {\n      console.log('Cell edited:', { newValue, row });\n      // Update your data source\n    },\n  },\n];\n\n<Table\n  id=\"editable-table\"\n  data={data}\n  columns={columns}\n  editMode=\"dblclick\" // or \"click\"\n  showEditIcon\n/>\n```\n\n## Props Reference\n\n### Core Props\n- `id`: Unique table identifier (required)\n- `data`: Array of data objects (required)\n- `columns`: Array of column definitions (required)\n- `keyField`: Field name for unique row identification (default: '_id')\n\n### Pagination\n- `pagination`: Enable pagination (default: true)\n- `remote`: Server-side mode (default: true)\n- `totalSize`: Total records for server-side pagination\n- `onPageSizeChange`: Callback for page/size changes\n\n### Selection\n- `isSelectRow`: Enable row selection with checkboxes\n- `isSelectSort`: Show \"move selected to top\" button\n- `onSelectSort`: Callback when select-sort is clicked\n- `selectionActions`: Array of custom action icons/buttons\n- `onSelectedRow`: Callback when rows are selected\n\n### Filtering & Search\n- `filterable`: Enable column filters\n- `searchable`: Enable global search\n- `searchPlaceholder`: Search input placeholder\n\n### Sorting\n- `sort`: Controlled sort state\n- `defaultSort`: Default sort configuration\n- `multiSort`: Enable multi-column sorting\n\n### Export\n- `exportable`: Enable CSV export\n- `exportFileName`: Name for exported file\n- `exportFormat`: 'csv' or 'excel'\n\n## Selection Actions API\n\nEach action in `selectionActions` array supports:\n\n```tsx\n{\n  nameIcon: string;        // Icon name from react-icons (e.g., 'FaWhatsapp')\n  propsIcon?: {            // Props passed to Icon component\n    size?: string | number;\n    color?: string;\n    [key: string]: any;\n  };\n  onClick: (selectedRows: T[], selectedKeys: string[]) => void;\n  tooltip?: string;        // Tooltip text on hover\n  disabled?: boolean;      // Disable the action\n  className?: string;      // Custom CSS class\n}\n```\n\n## Examples\n\n### Basic Table\n```tsx\n<Table\n  id=\"basic-table\"\n  data={data}\n  columns={columns}\n/>\n```\n\n### With Pagination\n```tsx\n<Table\n  id=\"paginated-table\"\n  data={data}\n  columns={columns}\n  pagination\n/>\n```\n\n### With Row Selection\n```tsx\n<Table\n  id=\"selectable-table\"\n  data={data}\n  columns={columns}\n  isSelectRow\n  onSelectedRow={(rows) => console.log('Selected:', rows)}\n/>\n```\n\n### With Filters\n```tsx\n<Table\n  id=\"filtered-table\"\n  data={data}\n  columns={columns}\n  filterable\n  searchable\n/>\n```\n\n### Full Featured\n```tsx\n<Table\n  id=\"full-table\"\n  data={data}\n  columns={columns}\n  pagination\n  filterable\n  searchable\n  isSelectRow\n  isSelectSort\n  selectionActions={[...]}\n  exportable\n  columnToggle\n  striped\n  hover\n  stickyHeader\n/>\n```\n        "},page:null},layout:"padded"}},Documentation={parameters:{docs:{page:null,description:{story:"See the main documentation above for usage examples and API reference."}}}},BasicUsage={parameters:{docs:{page:null,description:{story:"Basic table usage example. See the main documentation for code examples."}}}},WithSelectionActions={parameters:{docs:{page:null,description:{story:"Table with row selection and dynamic action buttons. See the main documentation for code examples."}}}},__namedExportsOrder=["Documentation","BasicUsage","WithSelectionActions"];Documentation.parameters={...Documentation.parameters,docs:{...Documentation.parameters?.docs,source:{originalSource:"{\n  parameters: {\n    docs: {\n      page: null,\n      description: {\n        story: 'See the main documentation above for usage examples and API reference.'\n      }\n    }\n  }\n}",...Documentation.parameters?.docs?.source}}},BasicUsage.parameters={...BasicUsage.parameters,docs:{...BasicUsage.parameters?.docs,source:{originalSource:"{\n  parameters: {\n    docs: {\n      page: null,\n      description: {\n        story: 'Basic table usage example. See the main documentation for code examples.'\n      }\n    }\n  }\n}",...BasicUsage.parameters?.docs?.source}}},WithSelectionActions.parameters={...WithSelectionActions.parameters,docs:{...WithSelectionActions.parameters?.docs,source:{originalSource:"{\n  parameters: {\n    docs: {\n      page: null,\n      description: {\n        story: 'Table with row selection and dynamic action buttons. See the main documentation for code examples.'\n      }\n    }\n  }\n}",...WithSelectionActions.parameters?.docs?.source}}}}}]);